import torch
import torch.distributed as dist
import torch.nn.functional as F


class _AllGatherLastDim(torch.autograd.Function):
    """Differentiable all_gather that concatenates along the last dimension.

    Forward gathers every rank's tensor and concatenates them along the last
    dim (as if using all_gather). Backward takes only the slice that belongs to
    the local rank so gradients route back to the correct shard.
    """

    @staticmethod
    def forward(ctx, input_):
        world_size = dist.get_world_size()
        ctx.world_size = world_size
        ctx.rank = dist.get_rank()
        if world_size == 1:
            return input_
        input_ = input_.contiguous()
        tensors = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(tensors, input_)
        return torch.cat(tensors, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        if ctx.world_size == 1:
            return grad_output
        grad_chunks = grad_output.chunk(ctx.world_size, dim=-1)
        return grad_chunks[ctx.rank].contiguous()


class _AllReduceSum(torch.autograd.Function):
    """Differentiable all_reduce (sum). Backward is the identity."""

    @staticmethod
    def forward(ctx, input_):
        if dist.get_world_size() == 1:
            return input_
        output = input_.clone()
        dist.all_reduce(output, op=dist.ReduceOp.SUM)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    """Linear layer whose weight is split by columns (the output dimension).

    Weight convention follows ``torch.nn.Linear``: ``master_weight`` has shape
    ``[out_features, in_features]``. It is split along dim 0 (out_features) so
    each rank owns ``out_features // world_size`` rows. The per-rank outputs are
    all-gathered and concatenated along the last dimension. The bias is sharded
    the same way as the output dimension.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = dist.get_world_size()
        rank = dist.get_rank()

        self.in_features = in_features
        self.out_features = out_features
        self.out_features_per_partition = out_features // world_size

        weight_shard = master_weight.chunk(world_size, dim=0)[rank]
        self.weight = torch.nn.Parameter(weight_shard.contiguous().clone())

        if bias:
            self.bias = torch.nn.Parameter(
                torch.zeros(
                    self.out_features_per_partition,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight, self.bias)
        return _AllGatherLastDim.apply(local_output)


class RowParallelLinear(torch.nn.Module):
    """Linear layer whose weight is split by rows (the input dimension).

    ``master_weight`` has shape ``[out_features, in_features]`` and is split
    along dim 1 (in_features) so each rank owns
    ``in_features // world_size`` columns. Each rank's ``forward`` receives only
    its pre-scattered slice of the input (already partitioned along the last
    dimension). The partial outputs are summed via all_reduce. The bias is full
    on every rank and added after the reduction.
    """

    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = dist.get_world_size()
        rank = dist.get_rank()

        self.in_features = in_features
        self.out_features = out_features
        self.in_features_per_partition = in_features // world_size

        weight_shard = master_weight.chunk(world_size, dim=1)[rank]
        self.weight = torch.nn.Parameter(weight_shard.contiguous().clone())

        if bias:
            self.bias = torch.nn.Parameter(
                torch.zeros(
                    out_features,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight)
        output = _AllReduceSum.apply(local_output)
        if self.bias is not None:
            output = output + self.bias
        return output
